#pragma once

#include <imgui.h>

enum class GameStage {
    MainMenu,
    Playing,
    Results
};

struct StageData {
    GameStage current = GameStage::MainMenu;
    int score = 0;
    float playTime = 0.0f;
    bool paused = false;
    bool requestQuit = false;
};

void StartNewRun(StageData& data);
void SwitchStage(StageData& data, GameStage next);
void DrawMainMenu(StageData& data);
void UpdatePlaying(StageData& data, float deltaTime);
void DrawResults(StageData& data);

