#include "stage_types.hpp"

namespace {
void CenterWindow(float width, float height) {
    const ImVec2 display = ImGui::GetIO().DisplaySize;
    ImGui::SetNextWindowSize({width, height}, ImGuiCond_Always);
    ImGui::SetNextWindowPos(
        {(display.x - width) * 0.5f, (display.y - height) * 0.5f},
        ImGuiCond_Always
    );
}
}

void StartNewRun(StageData& data) {
    data.score = 0;
    data.playTime = 0.0f;
    data.paused = false;
    data.current = GameStage::Playing;
}

void SwitchStage(StageData& data, GameStage next) {
    if (data.current == next) {
        return;
    }

    data.current = next;

    if (next == GameStage::MainMenu) {
        data.paused = false;
    }
}

void DrawMainMenu(StageData& data) {
    CenterWindow(360.0f, 220.0f);
    ImGui::Begin("MainMenu", nullptr,
        ImGuiWindowFlags_NoResize |
        ImGuiWindowFlags_NoMove |
        ImGuiWindowFlags_NoCollapse |
        ImGuiWindowFlags_NoTitleBar);

    ImGui::TextUnformatted("نموذج تعدد المراحل");
    ImGui::Separator();
    ImGui::TextWrapped("هذه الشاشة لا تعرف منطق اللعب نفسه؛ دورها فقط اختيار بداية الجولة أو إنهاء التطبيق.");
    ImGui::Spacing();

    if (ImGui::Button("ابدأ اللعب", {200.0f, 38.0f})) {
        StartNewRun(data);
    }

    if (ImGui::Button("خروج", {200.0f, 38.0f})) {
        data.requestQuit = true;
    }

    ImGui::End();
}

void UpdatePlaying(StageData& data, float deltaTime) {
    if (!data.paused) {
        data.playTime += deltaTime;
        data.score += static_cast<int>(deltaTime * 12.0f);
    }

    ImGui::SetNextWindowPos({12.0f, 12.0f}, ImGuiCond_Always);
    ImGui::SetNextWindowSize({320.0f, 80.0f}, ImGuiCond_Always);
    ImGui::Begin("HUD", nullptr,
        ImGuiWindowFlags_NoResize |
        ImGuiWindowFlags_NoMove |
        ImGuiWindowFlags_NoCollapse |
        ImGuiWindowFlags_NoTitleBar);
    ImGui::Text("النقاط: %d", data.score);
    ImGui::Text("الوقت: %.1f ثانية", data.playTime);
    ImGui::End();

    CenterWindow(420.0f, 220.0f);
    ImGui::Begin("Playing", nullptr,
        ImGuiWindowFlags_NoResize |
        ImGuiWindowFlags_NoMove |
        ImGuiWindowFlags_NoCollapse |
        ImGuiWindowFlags_NoTitleBar);

    ImGui::TextUnformatted("مرحلة اللعب الحالية");
    ImGui::Separator();
    ImGui::TextWrapped("في مشروع فعلي ستوضع هنا update الخاصة بالعالم أو العدو أو اللاعب، بينما تبقى هذه الأزرار مجرد طبقة تحكم واجهية.");
    ImGui::Spacing();

    if (ImGui::Button(data.paused ? "استئناف" : "إيقاف مؤقت", {160.0f, 34.0f})) {
        data.paused = !data.paused;
    }
    ImGui::SameLine();
    if (ImGui::Button("إنهاء المرحلة", {160.0f, 34.0f})) {
        SwitchStage(data, GameStage::Results);
    }

    ImGui::TextDisabled("Esc يبدل pause أثناء اللعب.");
    ImGui::End();
}

void DrawResults(StageData& data) {
    CenterWindow(380.0f, 240.0f);
    ImGui::Begin("Results", nullptr,
        ImGuiWindowFlags_NoResize |
        ImGuiWindowFlags_NoMove |
        ImGuiWindowFlags_NoCollapse |
        ImGuiWindowFlags_NoTitleBar);

    ImGui::TextUnformatted("شاشة النتائج");
    ImGui::Separator();
    ImGui::Text("النقاط النهائية: %d", data.score);
    ImGui::Text("مدة الجولة: %.1f ثانية", data.playTime);
    ImGui::Spacing();

    if (ImGui::Button("إعادة اللعب", {200.0f, 36.0f})) {
        StartNewRun(data);
    }

    if (ImGui::Button("القائمة الرئيسية", {200.0f, 36.0f})) {
        SwitchStage(data, GameStage::MainMenu);
    }

    ImGui::End();
}

