#include <SDL3/SDL.h>
#include <imgui.h>
#include <imgui_impl_sdl3.h>
#include <imgui_impl_sdlrenderer3.h>
#include <cstdio>

#include "stage_types.hpp"

int main(int, char**) {
    if (!SDL_Init(SDL_INIT_VIDEO)) {
        std::printf("فشل SDL_Init: %s\\n", SDL_GetError());
        return 1;
    }

    SDL_Window* window = SDL_CreateWindow(
        "تعدد المراحل - SDL3 + ImGui",
        960,
        640,
        SDL_WINDOW_RESIZABLE
    );
    if (!window) {
        std::printf("فشل إنشاء النافذة: %s\\n", SDL_GetError());
        SDL_Quit();
        return 1;
    }

    SDL_Renderer* renderer = SDL_CreateRenderer(window, nullptr);
    if (!renderer) {
        std::printf("فشل إنشاء المصير: %s\\n", SDL_GetError());
        SDL_DestroyWindow(window);
        SDL_Quit();
        return 1;
    }

    IMGUI_CHECKVERSION();
    ImGui::CreateContext();
    ImGuiIO& io = ImGui::GetIO();
    io.ConfigFlags |= ImGuiConfigFlags_NavEnableKeyboard;

    ImGui_ImplSDL3_InitForSDLRenderer(window, renderer);
    ImGui_ImplSDLRenderer3_Init(renderer);

    StageData stageData;
    Uint64 lastCounter = SDL_GetPerformanceCounter();
    bool running = true;

    while (running) {
        SDL_Event event;
        while (SDL_PollEvent(&event)) {
            ImGui_ImplSDL3_ProcessEvent(&event);

            if (event.type == SDL_EVENT_QUIT) {
                running = false;
            }

            if (event.type == SDL_EVENT_KEY_DOWN &&
                event.key.key == SDLK_ESCAPE &&
                stageData.current == GameStage::Playing) {
                stageData.paused = !stageData.paused;
            }
        }

        const Uint64 now = SDL_GetPerformanceCounter();
        const float deltaTime = static_cast<float>(
            (now - lastCounter) /
            static_cast<double>(SDL_GetPerformanceFrequency())
        );
        lastCounter = now;

        ImGui_ImplSDLRenderer3_NewFrame();
        ImGui_ImplSDL3_NewFrame();
        ImGui::NewFrame();

        switch (stageData.current) {
            case GameStage::MainMenu:
                DrawMainMenu(stageData);
                break;
            case GameStage::Playing:
                UpdatePlaying(stageData, deltaTime);
                break;
            case GameStage::Results:
                DrawResults(stageData);
                break;
        }

        if (stageData.requestQuit) {
            running = false;
        }

        ImGui::Render();
        SDL_SetRenderDrawColor(renderer, 20, 22, 30, 255);
        SDL_RenderClear(renderer);
        ImGui_ImplSDLRenderer3_RenderDrawData(ImGui::GetDrawData());
        SDL_RenderPresent(renderer);
    }

    ImGui_ImplSDLRenderer3_Shutdown();
    ImGui_ImplSDL3_Shutdown();
    ImGui::DestroyContext();
    SDL_DestroyRenderer(renderer);
    SDL_DestroyWindow(window);
    SDL_Quit();
    return 0;
}
